"use strict";parserFactory.register("akknovel.com",()=>new AkknovelParser);class AkknovelParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.chapter-item a")].map(e=>this.linkToChapter(e))}linkToChapter(e){let t=e.querySelector("span"),r=t.textContent.trim()+" "+t.nextSibling.textContent.trim();return{sourceUrl:e.href,title:r}}findContent(e){return e.querySelector("#chr-content")||e.querySelector("#chapter-content")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h1").textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.aspect-h-4")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.leading-7")]}}